INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-a-and-m-university'), 'TAMU Microgravity Team', 'Historical/Design Team', 'Space', 'Direct', 'Participated in NASA''s Reduced Gravity Education Flight Program conducting zero-G experiments.', '[https://microgravity.tamu.edu/](https://www.google.com/search?q=https://microgravity.tamu.edu/)');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Texas State Space Lab (Space Lab)', 'Research Lab', 'Satellite', 'Direct', 'The Space Lab is a student-run research facility dedicated to developing space technology, small satellites (CubeSats), and ground-station operations.', 'https://txstspacelab.org/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Society for Space Exploration (SSE)', 'Student Org', 'Space Exploration', 'Direct', 'SSE is a research-driven student organization (SEDS Texas State chapter) that focuses on space technology, balloon missions, and small satellite development.', 'https://www.instagram.com/sse_txst/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Bobcat Aerospace', 'Student Org', 'Propulsion', 'Direct', 'Bobcat Aerospace is a student-led organization at Texas State focused on high-powered rocketry, propulsion systems, and aerospace engineering projects.', 'https://www.instagram.com/bobcataero/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Astronomy Club', 'Student Org', 'Astrophysics', 'Direct', 'The Astronomy Club is dedicated to exploring the night sky, educational outreach, and operating the campus observatory for public viewing.', 'https://www.astrotxst.org/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Robotics & Control (ROBOCO) Lab', 'Research Lab', 'Robotics', 'Direct', 'The ROBOCO Lab conducts research on sensor fusion, artificial intelligence, and control systems for robotics and intelligent transportation.', 'https://roboco.wp.txstate.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Texas State Observatory', 'Facility', 'Astrophysics', 'Direct', 'Located atop the Supple Science Building, the observatory is a research and public education facility equipped with a 16-inch telescope.', 'https://www.txst.edu/physics/observatory.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'NASA STEM Educator Professional Development Collaborative (EPDC)', 'Center/Program', 'Space Education', 'Direct', 'This NASA-funded collaborative at Texas State provides professional development for educators to engage students in NASA''s missions and STEM.', 'https://news.txst.edu/research-and-innovation/2021/nasa-extends-research-program.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'X-Bow Systems Cooperative Research Partnership', 'Research Partnership', 'Propulsion', 'Direct', 'A cooperative research agreement between Texas State and X-Bow Systems to test and validate advanced solid rocket motor technology.', 'https://news.txst.edu/research-and-innovation/2024/txst-partners-with-xbow-systems-for-solid-rocket-motor-advancement.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Texas State Mars Drillers', 'Design Team', 'Robotics', 'Direct', 'The Mars Drillers is a manufacturing engineering team that competes in the NASA Texas Space Grant Consortium Design Challenge, developing robotic drills for planetary exploration.', 'https://rpd.engineering.txst.edu/nasa.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Space Workforce Incubator for Texas (SWIFT)', 'Center/Program', 'Space Exploration', 'Direct', 'SWIFT is an initiative aimed at preparing the Texas workforce for the booming aerospace and space exploration industry.', 'https://www.txst.edu/physics/banzatti-seminar/expo-attendees.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Society of Physics Students (SPS) - Texas State Chapter', 'Student Org', 'Astrophysics', 'Strongly Adjacent', 'The Texas State chapter of SPS regularly hosts events and speakers from organizations like NASA, focusing on astrophysics and professional development in physics.', 'https://www.cose.txst.edu/cose-majors/student-organizations.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'IEEE Texas State - Robotics and Automation Society (RAS)', 'Student Org', 'Robotics', 'Strongly Adjacent', 'The IEEE branch at Texas State includes a focus on robotics and automation, often utilizing the makerspace for technical projects.', 'https://cs.txst.edu/resources/student-involvement.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Advanced Composites Laboratory', 'Research Lab', 'Aerospace', 'Strongly Adjacent', 'This lab conducts research on composite materials used in aerospace applications and has strong leadership ties to the Bobcat Aerospace rocketry club.', 'https://composites.engineering.txst.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Icarus Project', 'Research Project', 'Satellite', 'Direct', 'The Icarus project is a mission within the Space Lab and SSE to develop and launch balloon-borne experiments and small satellites.', 'https://txstspacelab.org/?page_id=68');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'Rapid Product and Process Development (RPD) Center', 'Research Center', 'Robotics', 'Direct', 'The RPD Center houses various NASA-funded projects and teams, including the Mars Drillers and robotic exploration initiatives.', 'https://rpd.engineering.txst.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'NASA Texas Space Grant Consortium (TSGC) - Texas State Delegation', 'University Group', 'Space Exploration', 'Direct', 'As a member institution of the TSGC, Texas State students and faculty participate in NASA-funded design challenges, scholarships, and research grants.', 'https://ig.utexas.edu/tsgc/member-institutions/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'ASME Texas State Chapter', 'Student Org', 'Robotics', 'Strongly Adjacent', 'The ASME chapter at Texas State frequently participates in mechanical design and robotics projects, including those related to aerospace technology.', 'https://www.engineering.txst.edu/current-students/organizations.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'texas-state-university'), 'AFROTC Detachment 840 (Aerospace Studies)', 'Academic/Student Org', 'Aerospace', 'Strongly Adjacent', 'The Department of Aerospace Studies (AFROTC) trains future Air Force and Space Force officers, offering specialized courses and leadership training in aerospace topics.', 'https://www.afrotc.txst.edu/');
