INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-cooper-union'), 'ASME Student Branch', 'Student Organization', 'Robotics / Mechanical Engineering', 'high', 'partial', 'https://cooper.edu/engineering/extracurricular/professional-societies');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Texas Rocket Engineering Lab (TREL)', 'design team / student project research lab', 'Rockets', 'Direct', 'Interdisciplinary undergraduate rocket program building and testing liquid-fueled rockets with the explicit goal of reaching space. It is one of UT Austin’s clearest student rocket organizations.', 'https://texasrocketlab.ae.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Longhorn Rocketry Association (LRA)', 'student org / design team', 'Rockets', 'Direct', 'Student-run high-power rocketry group that designs, builds, tests, and launches rockets and competes in the Spaceport America Cup. It is directly relevant to student rocketry.', 'https://sites.utexas.edu/sec/organizations/lra/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Texas Spacecraft Laboratory (TSL)', 'lab / student research group', 'Satellites', 'Direct', 'Student-driven lab dedicated to designing, building, launching, and operating small satellites and CubeSat-like missions. Its missions also include lunar navigation and high-altitude balloon testbeds.', 'https://sites.utexas.edu/tsl/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'UT Austin Chapter of AIAA', 'student org', 'Space', 'Direct', 'Official student chapter of the American Institute of Aeronautics and Astronautics for students interested in aviation and space. It is a core campus organization for aerospace and space-engaged students.', 'https://www.ae.utexas.edu/undergraduate/student-community/leadership-and-networking-organizations');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Astronomy Students Association (ASA)', 'student org', 'Astronomy', 'Direct', 'Student organization centered around astronomy and space science, with talks, outreach, observatory trips, and an astronomy learning community. It is directly space-related on the science side.', 'https://astronomy.utexas.edu/academics-overview/student-association');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Texas Flight', 'design team / student org', 'UAV/Avionics', 'Strongly Adjacent', 'Student-run aircraft design team competing in AIAA Design Build Fly. It is aviation-first rather than space-first, but it develops avionics, flight test, and aerospace systems skills adjacent to space engineering.', 'https://sites.utexas.edu/texasflight/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Unmanned Aerial Vehicles Austin (UAVA)', 'student org / design team', 'UAV/Avionics', 'Strongly Adjacent', 'Student team focused on hardware and software for autonomous fixed-wing aircraft in AUVSI SUAS. Its autonomy, controls, avionics, and air vehicle systems work is strongly adjacent to space robotics and guidance.', 'https://sites.utexas.edu/sec/organizations/uava/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Center for Space Research (CSR)', 'center', 'Space', 'Direct', 'Major UT research center spanning space and Earth sciences with work in geodesy, celestial mechanics, orbit determination, remote sensing, and space missions. This is one of UT’s principal institutional space hubs.', 'https://csr.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Space and Geophysics Laboratory (SGL), ARL:UT', 'lab', 'Remote Sensing', 'Strongly Adjacent', 'ARL:UT laboratory conducting research in electromagnetic propagation, geopositioning, and remote sensing. It is clearly space-adjacent through sensing, positioning, and space/geophysics work.', 'https://wwwext.arlut.utexas.edu/sgl.shtml');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Multispectral Imaging Research Analysis (MIRA) Laboratory, ARL:UT', 'lab', 'Remote Sensing', 'Strongly Adjacent', 'Remote sensing group at ARL:UT working with multispectral imaging and analysis. Its work is relevant because remote sensors are often satellite- or aircraft-borne and directly support space-derived Earth observation.', 'https://wwwext.arlut.utexas.edu/mira/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Radionavigation Laboratory (RNL)', 'lab', 'UAV/Avionics', 'Strongly Adjacent', 'Research lab in secure and precise positioning, navigation, timing, and remote sensing. Although broader than space, its navigation and tracking work is highly relevant to spacecraft autonomy, satellite applications, and guidance.', 'https://radionavlab.ae.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Department of Astronomy', 'departmental program', 'Astronomy', 'Direct', 'UT Austin’s astronomy department conducts frontier research across cosmology, stars, planets, instrumentation, and observatory-based science. It is an obvious academic home for space science on campus.', 'https://astronomy.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'McDonald Observatory', 'observatory / university research facility', 'Astronomy', 'Direct', 'University observatory with telescopes, instruments, research programs, and student-facing opportunities in observational astronomy. It is a major UT-affiliated astronomy institution.', 'https://mcdonald.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Center for Planetary Systems Habitability (CPSH)', 'center', 'Planetary', 'Direct', 'Interdisciplinary UT center linking astronomy, geosciences, engineering, and other fields around planetary systems and habitability. It is directly relevant to astrobiology and planetary science.', 'https://habitability.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'UT Institute for Geophysics (UTIG)', 'institute', 'Planetary', 'Direct', 'Research institute explicitly focused on understanding Earth and other planets. It is broader than space engineering, but planetary geophysics is a direct part of its mission.', 'https://ig.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'UTIG Polar and Planetary', 'research group / institute program', 'Planetary', 'Direct', 'UTIG’s Polar and Planetary program uses space-based and other geophysical methods to study planetary and icy-world processes. It is directly relevant to planetary science and mission science.', 'https://ig.utexas.edu/polar-and-planetary/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Texas Space Grant Consortium (TSGC)', 'consortium / program', 'Space', 'Direct', 'NASA-linked statewide consortium administered at UT Austin that supports space research, education, fellowships, and student design work. It is not a student club, but it is a central UT-affiliated space program.', 'https://ig.utexas.edu/tsgc/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Texas Space Grant Design Challenge', 'student design program', 'Space', 'Direct', 'NASA-sponsored design competition administered by the Texas Space Grant Consortium for undergraduate teams tackling NASA research objectives. It functions as a recurring student-facing space design program.', 'https://ig.utexas.edu/designchallenge/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Fusion Research Center (FRC)', 'center', 'Plasma', 'Strongly Adjacent', 'UT center conducting experimental plasma physics and fusion research using tokamaks and plasma devices. It is not space-focused, but plasma science is materially adjacent to propulsion and space plasma topics.', 'https://www.frc.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Institute for Fusion Studies (IFS)', 'institute', 'Plasma', 'Strongly Adjacent', 'National center for plasma physics and fusion energy science at UT. It is more energy-oriented than aerospace, but still clearly adjacent through plasma physics relevant to space environments and propulsion concepts.', 'https://physics.utexas.edu/research/centers-institutes/institute-fusion-studies');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Texas Robotics', 'center / research community', 'Robotics', 'Strongly Adjacent', 'Campus-wide robotics entity connecting multiple labs and autonomy research efforts. It is not dedicated to space, but robotics and long-term autonomy are meaningfully adjacent to space operations and exploration systems.', 'https://robotics.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Center for Autonomy', 'center', 'Robotics', 'Strongly Adjacent', 'Research center focused on autonomous systems through controls, machine learning, and formal methods. It is space-adjacent because these capabilities map directly to autonomous vehicles and robotic mission systems.', 'https://autonomy.oden.utexas.edu/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Digital Landscape Laboratory (DLL Lab)', 'lab', 'Remote Sensing', 'Loosely Adjacent', 'GIS and remote sensing facility in Geography supporting modeling and characterization of Earth processes. It is loosely space-adjacent because satellite remote sensing is part of its core technical stack.', 'https://cla.utexas.edu/geography/research/labs-facilities/dll-lab.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'GIS Center (Geography and the Environment)', 'center / facility', 'Remote Sensing', 'Loosely Adjacent', 'UT Geography center supporting teaching and research in GIS and remote sensing. It is more Earth-observation oriented than space-oriented, but still relevant to satellite data and geospatial sensing.', 'https://liberalarts.utexas.edu/geography/undergraduate-program/gis-center.html');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Senior Spacecraft Mission Design Project Showcase', 'departmental program', 'Space', 'Direct', 'Recurring aerospace capstone sequence where teams design spacecraft and missions for space-related challenges, including lunar and Mars concepts. It is a student-facing space systems program embedded in the department.', 'https://www.ae.utexas.edu/undergraduate/senior-spacecraft-mission-design-project-showcase');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Space Systems and Astrodynamics (ASE/EM research area)', 'departmental research area', 'Space', 'Direct', 'Aerospace research area covering trajectory and mission design, nonlinear estimation, space geodesy, remote sensing, and satellite applications. It is a direct institutional home for space systems research.', 'https://www.ae.utexas.edu/research/space-systems-and-astrodynamics');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Controls, Autonomy and Robotics (ASE/EM research area)', 'departmental research area', 'Robotics', 'Strongly Adjacent', 'Aerospace research area applying controls, autonomy, and robotics to navigation, guidance, and flight mechanics of vehicles across domains. It is strongly adjacent because those methods are central to spacecraft and robotic space systems.', 'https://www.ae.utexas.edu/research/controls-autonomy-robotics');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Aerothermodynamics and Fluid Mechanics (ASE/EM research area)', 'departmental research area', 'Plasma', 'Strongly Adjacent', 'Aerospace research area including hypersonics, combustion, plasma science and engineering, and gas dynamics in space science. It is not an organization in the club sense, but it is a meaningful UT research grouping for space-adjacent work.', 'https://www.ae.utexas.edu/research/aerothermodynamics-and-fluid-mechanics');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Texas Eclipse Ballooning Project (TEBP)', 'capstone project team', 'High-Altitude Balloons', 'Direct', 'Aerospace senior capstone team that built and launched a high-altitude balloon payload for eclipse research. It is clearly space-adjacent, but appears to be a one-off project team rather than a standing organization.', 'https://www.ae.utexas.edu/news/a-stratospheric-view-with-the-texas-eclipse-ballooning-project');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'the-university-of-texas-at-austin'), 'Texas Space Society', 'student org', 'Space', 'Loosely Adjacent', 'Widely referenced as a UT student space organization, but I did not confirm a current official UT-hosted page in this pass. It likely belongs in the main table if an official campus or HornsLink page is available.', NULL);
