INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'i5 Club', 'Student Club', 'Space', 'Direct', 'The Institute for Applied Space Policy and Strategy (i5) educates midshipmen on space policy, doctrine, and warfighting capabilities.', 'https://www.usna.edu/SSEL/Clubs_and_Activities.php');
