INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'RaVision', 'Research Group', 'Robotics', 'Direct', 'Robotics and Autonomous Vehicles in Support of the Navy (RA-VISION) conducts research in autonomous systems and human-robot interaction.', 'https://www.usna.edu/WRC/research/groups/RaVision/index.php');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'ARTeMis Lab', 'Lab', 'Robotics', 'Direct', 'The Aerial Robotics Testing and Mission Lab is a facility for developing and testing autonomous aerial vehicles.', 'https://www.usna.edu/WRC/facilities/ARTeMis.php');
