INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'Astronomy Club', 'Student Club', 'Space', 'Direct', 'A student organization focused on observational astronomy, utilizing the Class of 1941 Observatory for research and casual observing.', 'https://www.usna.edu/PhysicsDepartment/Facilities/Classof1941Observatory.php');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'AIAA Student Chapter', 'Student Club', 'Aerospace', 'Direct', 'The USNA branch of the American Institute of Aeronautics and Astronautics supports student interest and professional development in aerospace engineering.', 'https://www.usna.edu/AeroDept/prospective-students/internships.php');
