INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'Powered Flight Program (PFP)', 'Military-only Training Unit', 'Aerospace', 'Direct', 'A summer training program that introduces midshipmen to aviation through formal flight instruction and simulations.', 'https://www.usna.edu/AeroDept/prospective-students/internships.php');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'MIDSTAR Satellite Project', 'Lab', 'Space', 'Direct', 'A historical project within the Small Satellite Program that developed the MIDSTAR-1 satellite launched in 2007.', 'https://www.usna.edu/SSEL/index.php');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'Association of Naval Aviation (ANA) - Two Block Fox Squadron', 'Alumni Association group', 'Aerospace', 'Direct', 'A professional and alumni-focused organization supporting naval aviation, with an active squadron at the Naval Academy.', 'https://www.anahq.org/');
INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'united-states-naval-academy'), 'Rotor Lab', 'Lab', 'Aerospace', 'Direct', 'Houses a full-size helicopter rotor test cell for undergraduate research in rotary-wing aircraft.', 'https://www.usna.edu/AeroDept/LabSpaces.php');
