INSERT OR REPLACE INTO organization (institution_id, name, type, category, relevance, confidence, website) VALUES ((SELECT id FROM institution WHERE slug = 'university-at-buffalo'), 'Students for the Exploration and Development of Space (UB SEDS)', 'Student Club', 'Space Exploration / Rocketry / Astronomy', 'Direct', 'A student-led organization that raises interest in space exploration through projects in rocketry, high-altitude balloons, and astronomy.', 'https://www.ubseds.org/');
